  let inserted = 0;
  for (const tmpl of ALL_TEMPLATES) {
    const existing = await pool.query('SELECT id FROM canvas_templates WHERE name = $1', [tmpl.name]);
    if (existing.rows.length === 0) {
      await pool.query(
        `INSERT INTO canvas_templates (name, industry, category, canvas_json, canvas_width, canvas_height, sort_order)
         VALUES ($1, $2, $3, $4, $5, $6, $7)`,
        [tmpl.name, tmpl.industry, tmpl.category, JSON.stringify(tmpl.canvas_json), tmpl.canvas_width || 1080, tmpl.canvas_height || 1350, tmpl.sort_order]
      );
      inserted++;
    }
  }
  console.log(`Inserted ${inserted} new templates`);

  const { rows } = await pool.query('SELECT count(*) FROM canvas_templates');
  console.log(`Total templates now in DB: ${rows[0].count}`);
